import sys

def main():
    N, T, P = map(int, sys.stdin.readline().split())
    L = list(map(int, sys.stdin.readline().split()))

    count = 0
    for l in L:
        if l >= T:
            count += 1
    if count >= P:
        print(0)
        return

    days = 0
    while True:
        days += 1
        new_count = 0
        for l in L:
            if l + days >= T:
                new_count += 1
        if new_count >= P:
            print(days)
            return

if __name__ == "__main__":
    main()
